import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.Gson;
import com.google.gson.TypeAdapter;
import com.google.gson.internal.bind.ReflectiveTypeAdapterFactory;
import com.google.gson.reflect.TypeToken;
import com.google.gson.stream.JsonWriter;
import java.io.IOException;
import java.lang.reflect.Type;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.ArgumentCaptor;
import org.mockito.Mock;
import org.mockito.MockitoAnnotations;

final class TypeAdapterRuntimeTypeWrapperTest {

  @Mock Gson mockGson;
  @Mock TypeAdapter<Object> mockDelegate;
  @Mock TypeAdapter<Object> mockRuntimeTypeAdapter;
  @Mock JsonWriter mockJsonWriter;

  TypeAdapterRuntimeTypeWrapper<Object> wrapper;
  Type declaredType = Object.class;

  @BeforeEach
  void setUp() {
    MockitoAnnotations.openMocks(this);
    wrapper = new TypeAdapterRuntimeTypeWrapper<>(mockGson, mockDelegate, declaredType);
  }

  @Test
  void write_runtimeTypeEqualsDeclaredType_usesDelegateWrite() throws IOException {
    Object value = new Object();

    // Stub getRuntimeTypeIfMoreSpecific to return declaredType to simulate no runtime type difference
    // Use reflection to override private static method getRuntimeTypeIfMoreSpecific
    // Since it's private static, we cannot easily mock it, so we test with value of declared type
    // which will lead to runtimeType == declaredType
    wrapper.write(mockJsonWriter, value);

    verify(mockDelegate).write(mockJsonWriter, value);
    verifyNoMoreInteractions(mockRuntimeTypeAdapter, mockGson);
  }

  @Test
  void write_runtimeTypeDifferent_runtimeTypeAdapterNotReflective_usesRuntimeTypeAdapterWrite() throws IOException {
    Object value = "string"; // runtime type String.class different from declaredType Object.class

    when(mockGson.getAdapter(TypeToken.get(String.class))).thenReturn(mockRuntimeTypeAdapter);
    when(mockRuntimeTypeAdapter instanceof ReflectiveTypeAdapterFactory.Adapter).thenReturn(false);

    // Spy wrapper to mock getRuntimeTypeIfMoreSpecific to return String.class
    TypeAdapterRuntimeTypeWrapper<Object> spyWrapper = spy(wrapper);
    doReturn(String.class).when(spyWrapper).getRuntimeTypeIfMoreSpecific(declaredType, value);

    spyWrapper.write(mockJsonWriter, value);

    verify(mockRuntimeTypeAdapter).write(mockJsonWriter, value);
    verify(mockDelegate, never()).write(any(), any());
  }

  @Test
  void write_runtimeTypeDifferent_runtimeTypeAdapterReflective_delegateNotReflective_usesDelegateWrite() throws IOException {
    Object value = "string";

    when(mockGson.getAdapter(TypeToken.get(String.class))).thenReturn(mockRuntimeTypeAdapter);

    // Make runtimeTypeAdapter instance of ReflectiveTypeAdapterFactory.Adapter
    ReflectiveTypeAdapterFactory.Adapter reflectiveAdapter = mock(ReflectiveTypeAdapterFactory.Adapter.class);
    when(mockGson.getAdapter(TypeToken.get(String.class))).thenReturn(reflectiveAdapter);

    // Spy wrapper to mock getRuntimeTypeIfMoreSpecific to return String.class
    TypeAdapterRuntimeTypeWrapper<Object> spyWrapper = spy(wrapper);
    doReturn(String.class).when(spyWrapper).getRuntimeTypeIfMoreSpecific(declaredType, value);

    // Spy wrapper to mock isReflective to return false for delegate
    doReturn(false).when(spyWrapper).isReflective(mockDelegate);

    spyWrapper.write(mockJsonWriter, value);

    verify(mockDelegate).write(mockJsonWriter, value);
    verify(reflectiveAdapter, never()).write(any(), any());
  }

  @Test
  void write_runtimeTypeDifferent_runtimeTypeAdapterReflective_delegateReflective_usesRuntimeTypeAdapterWrite() throws IOException {
    Object value = "string";

    ReflectiveTypeAdapterFactory.Adapter reflectiveAdapter = mock(ReflectiveTypeAdapterFactory.Adapter.class);
    when(mockGson.getAdapter(TypeToken.get(String.class))).thenReturn(reflectiveAdapter);

    TypeAdapterRuntimeTypeWrapper<Object> spyWrapper = spy(wrapper);
    doReturn(String.class).when(spyWrapper).getRuntimeTypeIfMoreSpecific(declaredType, value);

    doReturn(true).when(spyWrapper).isReflective(mockDelegate);

    spyWrapper.write(mockJsonWriter, value);

    verify(reflectiveAdapter).write(mockJsonWriter, value);
    verify(mockDelegate, never()).write(any(), any());
  }
}
